const items = $input.all();
const loopItems = $('ONE: LOOP').all();

// Fallback when SQL returns no matching rows
if (items.length === 1 && items[0].json.success === true) {
  return loopItems.map(li => ({
    json: {
      success: true,
      row_number: li.json.row_number,
      loop_organisation_name: li.json.organization_name,
    }
  }));
}

// Build a lookup map: lowercased name → loop item data
const loopMap = {};
for (const li of loopItems) {
  const name = li.json.organization_name?.trim().toLowerCase();
  if (name) {
    loopMap[name] = li.json;
  }
}

const grouped = {};
for (const item of items) {
  const data = item.json;
  const orgId = data.organisation_id;
  if (!grouped[orgId]) {
    grouped[orgId] = {
      organisation_id: data.organisation_id,
      organisation_name: data.organisation_name,
      organisation_active: data.organisation_active,
      products: [],
      _productIds: new Set()
    };
  }
  if (!grouped[orgId]._productIds.has(data.product_id)) {
    grouped[orgId]._productIds.add(data.product_id);
    grouped[orgId].products.push({
      product_source_id: data.product_source_id,
      product_id: data.product_id,
      product_name: data.product_name,
      source: data.source,
      raw_release_date: data.raw_release_date,
      release_date: data.release_date,
      release_priority: data.release_priority
    });
  }
}

// Track which loop names were matched
const matchedLoopNames = new Set();

const matchedResults = Object.values(grouped).map(org => {
  const { _productIds, ...cleanOrg } = org;
  const currentName = cleanOrg.organisation_name?.trim().toLowerCase();
  const matchedLoop = currentName && loopMap[currentName];
  if (matchedLoop) matchedLoopNames.add(currentName); // ← track matched
  return {
    json: {
      ...cleanOrg,
      ...(matchedLoop ? {
        row_number: matchedLoop.row_number,
        loop_organisation_name: matchedLoop.organization_name,
      } : {})
    }
  };
});

// Append unmatched loop items (no SQL data found for them)
const unmatchedResults = Object.entries(loopMap)
  .filter(([name]) => !matchedLoopNames.has(name))
  .map(([_, loopItem]) => ({
    json: {
      row_number: loopItem.row_number,
      loop_organisation_name: loopItem.organization_name,
    }
  }));

return [...matchedResults, ...unmatchedResults];

// VALID PORTAL IS PUBLISHER, DEVELOPER, CURATOR, FRANCHISE
const url = $json.portal?.trim();

const isValidPortal =
  url &&
  /^https:\/\/store\.steampowered\.com\/(publisher|developer|curator|franchise)\/[^\/]+\/?$/.test(url);

return [{
  row_number: $json.row_number,
  organization_name: $json.organization_name,
  portal: url,
  limit: $json.limit,
  portal_validation: isValidPortal ? 200 : 400
}];

