  const data = item.json;
  const portal = data.portal || '';

  // Remove the base Steam URL
  const trimmed = portal.replace('https://store.steampowered.com/', '');

  // Split into type and name
  const [org_steam_portal, org_steam_name] = trimmed.split('/');

  return {
