});

const agents = [
'Mozilla/5.0 (Windows NT 10.0; Win64; x64) Chrome/124.0.0.0 Safari/537.36',
'Mozilla/5.0 (Macintosh; Intel Mac OS X 14_4) Chrome/124.0.0.0 Safari/537.36',
'Mozilla/5.0 (X11; Linux x86_64) Chrome/123.0.0.0 Safari/537.36',
'Mozilla/5.0 (Windows NT 10.0; Win64; x64; rv:124.0) Gecko/20100101 Firefox/124.0',
];
const pick = Math.floor(Math.random() * agents.length);
return [{ json: { ...($input.first().json), userAgent: agents[pick] } }]

const data = Array.isArray($json) ? $json[0] : $json;
const totalCount = parseInt(data.total_count || '0', 10);

// Get source info from VALIDATE STEAM PORTAL node (exclude portal_validation)
const sourceRaw = $items("ONE: VALIDATE STEAM PORTAL")[0].json;
const sourceInfo = {
  row_number: sourceRaw.row_number,
  organization_name: sourceRaw.organization_name,
  portal: sourceRaw.portal,
  limit: sourceRaw.limit
};

const limit = parseInt(sourceRaw.limit || '1', 10);

// No upcoming games — return 404-equivalent
if (totalCount === 0) {
  return [{
    json: {
      status: 404,
      message: 'No upcoming game releases found',
      source: sourceInfo,
      games: []
    }
  }];
}

const html = data.results_html;
const games = [];

const blockRegex = /data-ds-appid="(\d+)"[\s\S]*?href="(https:\/\/store\.steampowered\.com\/app\/[^"]+)"[\s\S]*?<span class='color_created'>([\s\S]*?)<\/span>[\s\S]*?<span class="curator_review_date">([\s\S]*?)<\/span>/g;
let match;

while ((match = blockRegex.exec(html)) !== null) {
  if (games.length >= limit) break;

  games.push({
    appid: match[1],
    url: match[2],
    title: match[3].replace(/<[^>]+>/g, '').trim(),
    release_date: match[4].replace(/<[^>]+>/g, '').trim()
  });
}

return [{
  json: {
    status: 200,
    message: `Found ${games.length} upcoming game(s)`,
    source: sourceInfo,
    games
  }
}];

// Get all incoming items
